using System;
using System.Collections.Generic;
using System.Linq;

public class PatternBlobIndex
{
    // Core inverted indices
    private HashSet<Blob> Blobs = new();
    private HashSet<Mapping<Piece, HashSet<Blob>>> PieceToBlobs = new();
    private HashSet<Mapping<Bit, HashSet<Piece>>> BitToPieces = new();

    // Add a new blob pattern
    public void AddBlobPattern(string blobName, string sentence)
    {
        var blob = new Blob(blobName, new HashSet<Piece>());
        Blobs.Add(blob);

        var words = sentence.Split(' ');
        foreach (var word in words)
        {
            var piece = GetOrCreatePiece(word);
            blob.Value.Add(piece);

            foreach (var ngram in GenerateNGrams(word, 2)) // Using bigrams
            {
                var bit = GetOrCreateBit(ngram);
                bit.Value.Add(piece);
            }
        }
    }

    // Query processing
    public string ProcessQuery(string query)
    {
        var queryWords = query.Split(' ');
        var results = new List<string>();

        foreach (var queryWord in queryWords)
        {
            if (ContainsPiece(queryWord))
            {
                results.Add(queryWord); // Exact match
            }
            else
            {
                // Fuzzy match using bits
                var fuzzyMatch = FuzzyMatchPiece(queryWord);
                results.Add(fuzzyMatch ?? queryWord); // Use fuzzy match or leave unchanged
            }
        }

        return string.Join(' ', results);
    }

    // Helpers: World Scope (Bit <-> Pieces)
    private Bit GetOrCreateBit(string ngram)
    {
        var mapping = new Mapping<Bit, HashSet<Piece>>(new Bit(ngram), new HashSet<Piece>());
        if (!BitToPieces.TryGetValue(mapping, out var existing))
        {
            BitToPieces.Add(mapping);
            return mapping.Key;
        }
        return existing.Key;
    }

    private Piece GetOrCreatePiece(string word)
    {
        var mapping = new Mapping<Piece, HashSet<Blob>>(new Piece(word), new HashSet<Blob>());
        if (!PieceToBlobs.TryGetValue(mapping, out var existing))
        {
            PieceToBlobs.Add(mapping);
            return mapping.Key;
        }
        return existing.Key;
    }

    // Check if a piece exists
    private bool ContainsPiece(string word)
    {
        return PieceToBlobs.Contains(new Mapping<Piece, HashSet<Blob>>(new Piece(word), null));
    }

    // Fuzzy matching via bit-level n-grams
    private string FuzzyMatchPiece(string queryWord)
    {
        var queryNGrams = GenerateNGrams(queryWord, 2);
        var bestMatch = default(Piece);
        var bestScore = 0;

        foreach (var ngram in queryNGrams)
        {
            var bitMapping = new Mapping<Bit, HashSet<Piece>>(new Bit(ngram), null);
            if (BitToPieces.TryGetValue(bitMapping, out var existing))
            {
                foreach (var candidate in existing.Value)
                {
                    var score = queryNGrams.Count(ngram => candidate.Name.Contains(ngram));
                    if (score > bestScore)
                    {
                        bestScore = score;
                        bestMatch = candidate;
                    }
                }
            }
        }

        return bestMatch?.Name;
    }

    // Generate n-grams
    private IEnumerable<string> GenerateNGrams(string word, int n)
    {
        for (int i = 0; i <= word.Length - n; i++)
        {
            yield return word.Substring(i, n);
        }
    }

    // Universal Scope (Blobs <-> Pieces)
    public List<string> QueryBlobsContainingPiece(string pieceName)
    {
        var mapping = new Mapping<Piece, HashSet<Blob>>(new Piece(pieceName), null);
        if (PieceToBlobs.TryGetValue(mapping, out var existing))
        {
            return existing.Value.Select(blob => blob.Name).ToList();
        }
        return new List<string>();
    }
}

