            BitToPiece.Add(mapping);
            return mapping.Key;
        }
        return existing.Key;
    }

    // Universal scope: Piece -> Blob relationships
    private Piece GetOrCreatePiece(string word)
    {
        var mapping = new Mapping<Piece, HashSet<Blob>>(new Piece(word, new HashSet<Bit>()), new HashSet<Blob>());
        if (!PieceToBlob.TryGetValue(mapping, out var existing))
        {
            PieceToBlob.Add(mapping);
            return mapping.Key;
        }
        return existing.Key;
    }

    // Universal scope: Blob -> BLOB relationships
    private Blob GetOrCreateBlob(string sentence)
    {
        var mapping = new Mapping<Blob, HashSet<Piece>>(new Blob(sentence, new HashSet<Piece>()), new HashSet<Piece>());
        if (!BlobToBLOB.TryGetValue(mapping, out var existing))
        {
            BlobToBLOB.Add(mapping);
            return mapping.Key;
        }
        return existing.Key;
    }
