private IEnumerable<byte> Generate8BitMasks(string word)
{
    for (int i = 0; i < word.Length - 1; i++)
    {
        // Convert characters to 4-bit values
        byte left = (byte)(word[i] & 0x0F);   // Lower 4 bits
        byte right = (byte)(word[i + 1] & 0x0F); // Lower 4 bits of next character

        // Combine into an 8-bit mask
        yield return (byte)((left << 4) | right);
    }
}
