        ushort feature = (ushort)((charValue & kernel) >> (16 - windowSize));

        // Add the feature as a "digit" in the base-encoded signature
        signature += (ulong)(feature * baseValue);
        baseValue *= (1 << windowSize); // Shift base for next digit
    }

    return signature;
}
