// Generate all wildcard signatures
private IEnumerable<ulong> GenerateWildcardSignatures(ulong signature, int maxBitDifferences)
{
    var wildcards = new HashSet<ulong> { signature };

    for (int i = 0; i < 64; i++) // Assuming 64-bit signatures
