// Compute parity bits for a signature layer
private int[] ComputeParity(ulong signature, int layers, int bitsPerLayer)
{
    var parityBits = new int[layers];

    for (int i = 0; i < layers; i++)
    {
        ulong layer = (signature >> (i * bitsPerLayer)) & ((1UL << bitsPerLayer) - 1);
        parityBits[i] = CountSetBits(layer) % 2; // 1 for odd parity, 0 for even parity
    }

    return parityBits;
}

// Count set bits (Hamming weight)
private int CountSetBits(ulong value)
{
    int count = 0;
    while (value != 0)
    {
        count += (int)(value & 1);
        value >>= 1;
    }
    return count;
}
```

---

#### **Step 2: Checksum Calculation**
```csharp
// Compute checksum for a signature
private byte ComputeChecksum(ulong signature, int layers, int bitsPerLayer)
{
    byte checksum = 0;

    for (int i = 0; i < layers; i++)
    {
        ulong layer = (signature >> (i * bitsPerLayer)) & ((1UL << bitsPerLayer) - 1);
        checksum = (byte)((checksum + (byte)layer) % 256); // Sum modulo 256
    }

    return checksum;
}
```

