// Generate custom hash from signature, parity, and checksum
private int CustomHash(ulong signature, int[] parityBits, byte checksum)
{
    int hash = signature.GetHashCode();

    // Incorporate parity bits into the hash
    foreach (var bit in parityBits)
    {
        hash = (hash * 31) + bit;
    }

    // Incorporate checksum into the hash
    hash = (hash * 31) + checksum;

    return hash;
}
```

