    public Piece(string word, ushort kernel, int layers)
    {
        Word = word;
        Signature = GenerateSignature(word, kernel, layers); // Generate signature
        ParityBits = ComputeParity(Signature, layers, 8); // 8 bits per layer
        Checksum = ComputeChecksum(Signature, layers, 8); // Compute checksum
    }

    // Override GetHashCode to create a composite hash
    public override int GetHashCode()
    {
        int hash = Signature.GetHashCode(); // Start with the signature's hash
        foreach (var bit in ParityBits)
        {
            hash = (hash * 31) + bit; // Incorporate parity bits
        }
        hash = (hash * 31) + Checksum; // Incorporate checksum
        return hash;
    }

    // Override Equals to ensure object equality is based on all components
    public override bool Equals(object obj)
    {
        if (obj is not Piece other) return false;
        return Word == other.Word &&
               Signature == other.Signature &&
               Checksum == other.Checksum &&
               EqualityComparer<int[]>.Default.Equals(ParityBits, other.ParityBits);
    }
}
