### **Managing the Pattern Structure**

We will define a container class to manage the hierarchical structure of `Blob`, `Piece`, and `Bit`.

```csharp
public class PatternManager
{
    private HashSet<Blob> Blobs = new(); // Top-level blobs

    // Add a new Blob
    public void AddBlob(string blobKey)
    {
        var blob = new Blob(blobKey);
        Blobs.Add(blob);
    }

    // Add a new Piece to a specific Blob
    public void AddPieceToBlob(string blobKey, string pieceKey)
    {
        var blob = GetBlob(blobKey);
        if (blob == null) throw new Exception($"Blob '{blobKey}' not found.");

        var piece = new Piece(pieceKey);
        blob.AddPiece(piece);
    }

    // Add a new Bit to a specific Piece within a Blob
    public void AddBitToPiece(string blobKey, string pieceKey, string bitKey)
    {
        var blob = GetBlob(blobKey);
        if (blob == null) throw new Exception($"Blob '{blobKey}' not found.");

        var piece = GetPiece(blob, pieceKey);
        if (piece == null) throw new Exception($"Piece '{pieceKey}' not found in Blob '{blobKey}'.");

        var bit = new Bit(bitKey);
        piece.AddBit(bit);
    }

    // Retrieve a Blob by key
    private Blob GetBlob(string key)
    {
        foreach (var blob in Blobs)
        {
            if (blob.Key == key) return blob;
        }
        return null;
    }

    // Retrieve a Piece by key within a specific Blob
    private Piece GetPiece(Blob blob, string key)
    {
        foreach (var piece in blob.Value)
        {
            if (piece.Key == key) return piece;
        }
        return null;
    }

    // Display the entire structure
    public void DisplayStructure()
    {
        foreach (var blob in Blobs)
        {
            Console.WriteLine($"Blob: {blob.Key}");
            foreach (var piece in blob.Value)
            {
                Console.WriteLine($"\tPiece: {piece.Key}");
                foreach (var bit in piece.Value)
                {
                    Console.WriteLine($"\t\tBit: {bit.Key}");
                }
            }
        }
    }
}
```

